import VElement from '../DOM/VElement.js';
import {escapeHtml} from '../utils/Utils.js';

/**
 * Title class
 */
class Title {
  /**
   * Constructor for the Title object
   * @param {object} config
   */
  constructor(config) {
    this.config = config;
    this.text = 'Title Text';
  }
  /**
   * Returns the default config for the Title
   */
  static get defaults() {
    return {
      l: {
        top: {
          breakpoint: {
            width: 200,
            height: 150,
          },
        },
      },
      title: {
        enabled: true,
        text: 'Title',
        style: {
          'text-align': 'center',
          'width': '100%',
          'font-weight': 400,
          'font-size': '1.4rem',
          'color': '#444',
          'text-anchor': 'middle',
          'alignment-baseline': 'middle',
        },
      },
    };
  }

  /**
   * Render the title object
   * @return {object} a virtual dom object of the title
   */
  render() {
    // Add title to the outside of the chartSVG
    const title = new VElement('div', {
      class: ['title'],
    });
    title.innerHTML = escapeHtml(this.config.title.text);
    return title;
  }
}

export default Title;
