import VElement from '../DOM/VElement.js';
import * as Util from '../utils/Utils.js';

/**
 * Scale Class
 */
class Scale {
  /**
   * The scale constructor
   * @param {*} options
   */
  constructor(options) {
    Object.assign(this, options);
  }

  /**
   * Renders a scale object and ticks
   * @return {object} The scale elements
   */
  render() {
    const {type, config, stats, data} = this;
    const elements = {
      ticks: [],
      labels: [],
      guides: [],
    };
    const {min, max, ticks, step} = stats[type];

    /*
      Three types of scales:
      1. Positive linear
        - All values are positive, so we always start at 0.
      2. Negative linear
        - Values have some negative numbers, so we allow the starting index of the axis
          to be before 0.
      3. Key Scales - Associative data like in bar charts ('Monday': 343, 'Tuesday': 2343)
    */
    const zeroStart = true;
    const chartType = this.chartType;

    // Determine the posiiton of each tick/guide/label
    const negative = (min < 0);
    for (let index = 0; index < ticks; index++) {
      let position;
      let dataIndex;
      // Adjust position to be centered on nodes of bar charts
      if (
        (chartType === 'bar' || chartType === 'column') &&
        ((type ==='x' && config.plot.vertical) || (type === 'y' && !config.plot.vertical))
      ) {
        if (stats.associative) {
          // Align to the specific tick number
          const halfBarWidth = stats[type].scaleFactor / 2;
          const percentageOfTick = (index / (ticks-1));

          // Find the closest index in the dataset that the tick can match to
          dataIndex = Math.floor((stats[type].scaleLength-1) * percentageOfTick);
          if (dataIndex === stats[type].scaleLength) {
            dataIndex--;
          }
          position = Util.formatNumber(dataIndex * stats[type].scaleFactor + halfBarWidth);
        } else {
          position = Util.formatNumber(
              ((100 * (index / (ticks))) + (100 * ((index + 1) / (ticks)))) / 2,
          );
        }
      } else {
        position = Util.formatNumber(index * step * stats[type].scaleFactor);
      }

      // Scale logic will need to be adjusted to not draw these.
      if (position > 100) {
        continue;
      }

      if (type === 'x') {
        elements.ticks.push(new VElement('line', {
          'x1': position + '%',
          'y1': '0%',
          'x2': position + '%',
          'y2': '100%',
          'class': ['ticks', 'ticks-x'],
        }));
      } else {
        elements.ticks.push(new VElement('line', {
          'x1': '0%',
          'y1': position + '%',
          'x2': '100%',
          'y2': position + '%',
          'class': ['ticks', 'ticks-y'],
        }));
      }

      // GUIDES
      if (type === 'x') {
        if (index !== 0 && config.guides.x.enabled) {
          elements.guides.push(new VElement('line', {
            'x1': position + '%',
            'y1': '100%',
            'x2': position + '%',
            'y2': '0%',
            'class': ['guides', 'guides-x'],
          }));
        }
      } else {
        if (index !== ticks-1 && config.guides.y.enabled) {
          elements.guides.push(new VElement('line', {
            'x1': '0%',
            'y1': position + '%',
            'x2': '100%',
            'y2': position + '%',
            'class': ['guides', 'guides-y'],
          }));
        }
      }

      let label;
      let labelText;
      // LABELS

      if (type === 'x') {
        label = new VElement('div', {
          'style': `left: ${position}%`,
          'class': ['scale-label', 'scale-label-x'],
        });
      } else {
        label = new VElement('div', {
          'style': `top: ${position}%`,
          'class': ['scale-label', 'scale-label-y'],
        });
      }

      if (!Array.isArray(data[0].values)) {
        if (type === 'x') {
          if (config.plot.vertical) {
            // For bar/column, dataIndex is set above; for line/area, derive from tick index
            const keyIndex = dataIndex ?? Math.round(index * (stats.x.keys.length - 1) / Math.max(ticks - 1, 1));
            const keyText = stats.x.keys[keyIndex];
            labelText = `${keyText}`;
          } else {
            labelText = `${((index) * step)}`;
          }
        } else {
          if (config.plot.vertical) {
            labelText = `${max - ((index) * step)}`;
          } else {
            const keyIndex = dataIndex ?? Math.round(index * (stats.y.keys.length - 1) / Math.max(ticks - 1, 1));
            const keyText = stats.y.keys[keyIndex];
            labelText = `${keyText}`;
          }
        }
      } else {
        if (type === 'x') {
          if (negative) {
            labelText = `${min + (index * step)}`;
          } else {
            labelText = `${min + (index * step) + ((zeroStart) ? 0 : 1)}`;
          }
        } else {
          labelText = `${max - ((index) * step)}`;
        }
      }

      if (type === 'x' && Util.propertyExists(config, 'scale.label.x.format')) {
        try {
          labelText = config.scale.label.x.format(labelText);
        } catch (e) {
          console.warn('SVC: scale.label.x.format threw an error:', e);
        }
      } else if (type === 'y' && Util.propertyExists(config, 'scale.label.y.format')) {
        try {
          labelText = config.scale.label.y.format(labelText);
        } catch (e) {
          console.warn('SVC: scale.label.y.format threw an error:', e);
        }
      }

      // Set the value to the html
      label.innerHTML = labelText;
      elements.labels.push(label);
    }
    return elements;
  }
}

export default Scale;
