// Require all styles to be injected. These files are processed via webpack + autoprefixer
import layout from './Layout.js';
import legend from './Legend.js';
import responsive from './Responsive.js';
import tooltip from './Tooltip.js';

/**
 * Virtual Stylesheet
 */
class Stylesheet {
  /**
   * Creates the Stylesheet
   */
  constructor() {
    this.sheet = '';
    [layout, legend, responsive, tooltip].forEach((sheet) => {
      this.sheet += addJSONStyles(sheet);
    });
    this.rules = [];
  }

  /**
   * Add a CSS rule
   * @param {string} selector - A css selector
   * @param {object} rules - An object containing css key/value styles.
   */
  addRule(selector, rules) {
    let ruleStr = '';
    Object.keys(rules).forEach((prop) => {
      ruleStr += `${prop}: ${rules[prop]};`;
    });
    this.sheet += `.svc-${selector}{${ruleStr}}`;
  }

  /**
   * Appends raw css styles to the stylesheet
   * @param {*} str
   */
  addRaw(str) {
    this.sheet += str;
  }

  /**
   * Create CSS rules from an object, and the number of plots.
   * @param {*} styles
   * @param {*} plotLength
   * @return {string}
   */
  convertconfig(styles, plotLength) {
    // An object of breakpoints with the keys as breakpoint numbers, and the values as an array of classnames
    const breakpoints = {
      width: {},
      height: {},
    };
    // Create styles and mutate the breakpoints object to find all breakpoints.
    const rules = parseStyles(styles);

    const breakpointRules = parseBreakpoints(breakpoints);
    return rules + breakpointRules;


    /**
    * Parses a breakpoint object to create points where objects
    * should be hidden.
    * @param {Object} breakpoints - An array of breakpoint object
    * @return {string} media query as a string
    */
    function parseBreakpoints(breakpoints) {
      let ruleset = '';
      Object.keys(breakpoints).forEach((direction) => {
        Object.keys(breakpoints[direction]).forEach((point) => {
          // Create a media query for each point
          const classnames = breakpoints[direction][point];
          let rule = `@media(max-${direction}: ${point}px){`;
          // Double selectors for higher specificity instead of !important
          const names = classnames.map((classname) => {
            return `.svc-${classname}.svc-${classname}`;
          });
          rule += names.join(',');
          rule += '{ display: none; }';
          rule += '}';
          ruleset += rule;
        });
      });
      return ruleset;
    }

    /**
     * Parses the object into CSS rules
     * @param {*} obj
     * @param {*} key
     * @param {*} rules
     * @param {*} path
     * @return {string} The css ruleset
     */
    function parseStyles(obj, key = '', rules = '', path = []) {
      for (const prop in obj) {
        if (prop === 'style') {
          // Add style to stylesheet.
          let ruleset = '';
          for (const attr in obj[prop]) {
            if (Object.hasOwn(obj[prop], attr)) {
              ruleset += `${attr}:${obj[prop][attr]};`;
            }
          }

          // Determine classname. Each nested object will be separated by a '-'
          if (path.length === 0) {
            rules += `.svc-l-wrap * {${ruleset}}`;
          } else {
            const classname = path.reduce((a, b) => {
              return a += ((a === '') ? '' : '-') + b;
            }, '');
            rules += `.svc-${classname}{${ruleset}}`;
          }
        } else if (prop === 'instances') {
          const instances = obj[prop];
          for (let i = 0; i < plotLength; i++) {
            const instance = instances[i];
            if (!instance) {
              continue;
            }
            let ruleset = '';

            for (const attr in instance) {
              if (Object.hasOwn(instance, attr)) {
                ruleset += `${attr}:${instance[attr]};`;
              }
            }
            if (ruleset !== '') {
              const classname = path.reduce((a, b) => {
                return a += ((a === '') ? '' : '-') + b;
              }, '');
              rules += `.svc-${classname}-${i} {${ruleset}}`;
            }
          }
          // Generate breakpoint
        } else if (prop === 'breakpoint') {
          const classname = path.reduce((a, b) => {
            return a += ((a === '') ? '' : '-') + b;
          }, '');
          if (breakpoints.width[obj.breakpoint.width]) {
            breakpoints.width[obj.breakpoint.width].push(classname);
          } else {
            breakpoints.width[obj.breakpoint.width] = [classname];
          }
          if (breakpoints.height[obj.breakpoint.height]) {
            breakpoints.height[obj.breakpoint.height].push(classname);
          } else {
            breakpoints.height[obj.breakpoint.height] = [classname];
          }
        } else if (typeof obj[prop] === 'object') {
          path.push(prop);
          rules = parseStyles(obj[prop], prop, rules, path );
          path.pop();
        }
      }
      return rules;
    }
  }
}

/**
 * Interprets JSON styles into css
 * @param {*} obj
 * @param {*} sheet
 * @return {string} the CSS sheet
 */
function addJSONStyles(obj, sheet = '') {
  Object.keys(obj).forEach((selector) => {
    const rules = obj[selector];

    if (selector.startsWith('@media')) {
      sheet += selector + '{';
      Object.keys(rules).forEach((mediaSelector) => {
        sheet += mediaSelector + '{';
        const mediaRules = rules[mediaSelector];
        Object.keys(mediaRules).forEach((prop) => {
          sheet += convertCamelCaseToDash(prop) + ':' + mediaRules[prop] + ';';
        });
        sheet += '}';
      });
      sheet += '}';
      return;
    }

    sheet += selector + '{';
    Object.keys(rules).forEach((prop) => {
      sheet += convertCamelCaseToDash(prop) + ':' + rules[prop] + ';';
    });
    sheet += '}';
  });
  return sheet;
}


/**
 * Converts keys in the JSON obj that are camelcase into dash case for css
 * @param {*} str
 * @return {string}
 */
function convertCamelCaseToDash(str) {
  let output = '';
  str.split('').forEach((char) => {
    if (char === char.toUpperCase()) {
      output += '-';
    }
    output += char.toLowerCase();
  });
  return output;
}
export default Stylesheet;
