import Chart from './Chart.js';
import VElement from '../DOM/VElement.js';
import * as Util from '../utils/Utils.js';
import Baseline from '../components/Baseline.js';
import Scale from '../components/Scale.js';
import Tooltip from '../components/Tooltip.js';
import createMediaQueries from '../components/ScaleQueries.js';
import {
  TOOLTIP_DEBOUNCE_MS,
  TOOLTIP_HIDE_DELAY_MS,
  DEFAULT_Y_TICKS,
  DEFAULT_VALUE_TICKS,
  SCALE_BUFFER_PERCENT,
} from '../constants.js';

/**
 * Cartesian chart
 */
class Cartesian extends Chart {
  /**
   * Returns the default object configuration for the chart type
   * @return {object} Returns the defaults objct
   */
  static get defaults() {
    const sparkline = {
      width: 120,
      height: 120,
    };
    return {
      'l': {
        axis: {
          y: {
            breakpoint: sparkline,
            label: {
              breakpoint: {
                width: 300,
                height: 250,
              },
            },
          },
        },
        chart: {
          row: {
            1: {
              breakpoint: sparkline,
            },
          },
        },
      },
      'plot': {
        vertical: true,
      },
      'axis': {
        breakpoint: sparkline,
        x: {
          enabled: true,
        },
        y: {
          enabled: true,
        },
        label: {
          x: {
            enabled: true,
            text: 'Scale-X',
          },
          y: {
            enabled: true,
            text: 'Scale-Y',
          },
        },
        style: {
          'stroke': 'var(--chart-axis-color, #444)',
          'stroke-width': 0.3,
          'vector-effect': 'non-scaling-stroke',
        },
      },
      'baseline': {
        x: {},
        y: {},
        style: {
          'stroke': '#888',
          'stroke-width': 1,
        },
      },
      'ticks': {
        x: {
          enabled: true,
        },
        y: {
          enabled: true,
        },
        style: {
          'stroke-width': '1',
          'stroke': '#DDD',
        },
      },
      'guides': {
        breakpoint: sparkline,
        x: {
          enabled: true,
        },
        y: {
          enabled: true,
        },
        style: {
          'stroke': 'var(--chart-grid-color, #e4e4e4)',
          'stroke-dasharray': '0, 0',
          'stroke-width': 1,
          'stroke-linecap': 'round',
        },
      },
      'scale': {
        sorted: false,
        minFontSize: 5,
        maxItems: 15,
        label: {
          style: {
            'text-align': 'center',
          },
        },
      },
    };
  }

  /**
   * Returns the name of the chart
   * @return {string}
   */
  getName() {
    return super.getName();
  }

  /**
   * Parses the configuration object and applies it to the virtual DOM structure
   * @param {Object} structure - An object containing virtual dom elements
   * @return {Object} The Structure
   */
  parse(structure) {
    structure = super.parse(structure);

    const data = this.data;
    const stylesheet = this.stylesheet;
    const config = this.config;

    const {
      layoutChart,
      layoutXAxis,
      layoutYAxis,
      layoutOriginLeft,
      layoutOriginCenter,
      layoutOriginRight,
      layoutYTicks,
      layoutXTicks,
      layoutXAxisLabel,
      layoutYAxisLabel,
    } = structure;
    // Create and cache stats for use later when creating tooltip and legend interactions
    const stats = this.stats = this.calculateStats(data, this.config);
    this.data = data;

    // X & Y TICKS, GUIDES, LABELS
    // -----------------------
    ['x', 'y'].forEach((type) => {
      const elements = new Scale({
        type,
        config,
        stats,
        data,
        chartType: this.constructor.type,
      }).render();
      Object.keys(elements).forEach((section) => {
        if (section === 'labels') {
          elements[section].forEach((el) => {
            if (type === 'x') {
              layoutXAxis.appendChild(el);
            } else {
              layoutYAxis.appendChild(el);
            }
          });
        } else if (section === 'ticks') {
          // Experimental ticks
          if (type === 'x' && config.ticks.x.enabled) {
            elements[section].forEach((el) => {
              layoutXTicks.appendChild(el);
            });
          } else if (type === 'y' && config.ticks.y.enabled) {
            elements[section].forEach((el) => {
              layoutYTicks.appendChild(el);
            });
          }
        } else {
          // Create a group based on the type
          const g = new VElement('g', {
            class: [type + '-' + section],
          });
          elements[section].forEach((el) => {
            g.appendChild(el);
          });
          layoutChart.appendChild(g);
        }
      });
    });

    // X-AXIS
    // -----------------------
    if (config.axis.x.enabled) {
      layoutChart.appendChild(this.createAxis({
        type: 'x',
      }));
    }
    if (config.axis.label.x.enabled) {
      const axisLabel = new VElement('div', {
        class: ['l-axis-label-text-x'],
      });
      axisLabel.innerHTML = `<span class="svc-axis-label-x">${Util.escapeHtml(config.axis.label.x.text)}</span>`;
      layoutXAxisLabel.appendChild(axisLabel);
    }

    // Y-AXIS
    // -----------------------
    if (config.axis.y.enabled) {
      layoutChart.appendChild(this.createAxis({
        type: 'y',
      }));
    }

    if (config.axis.label.y.enabled) {
      const axisLabel = new VElement('div', {
        class: ['l-axis-y-label-text'],
      });
      axisLabel.innerHTML = `<span class="svc-axis-label-y">${Util.escapeHtml(config.axis.label.y.text)}</span>`;
      layoutYAxisLabel.appendChild(axisLabel);
    }

    // DUMMY LABELS
    // -----------------------
    // This is for the x&y axis to resize to the longest text,
    // since each label has position: absolute;
    const dummyYAxis = new VElement('div', {
      class: ['l-axis-y-label-dummy', 'axis-label-y'],
    });
    dummyYAxis.innerHTML = '0';
    layoutOriginLeft.appendChild(dummyYAxis);
    layoutYAxisLabel.appendChild(dummyYAxis);

    const dummyXTick = new VElement('div', {
      style: 'height: 1%; min-height:10px;',
    });
    layoutOriginCenter.appendChild(dummyXTick);


    const dummyLabel = new VElement('div', {
      class: ['l-origin-label', 'scale-label'],
    });

    if (stats.associative && !config.plot.vertical) {
      // Find the longest key string
      const keys = stats.y.keys;
      let longestLength = 0;
      keys.forEach((key) => {
        longestLength = (key.length > longestLength) ? key.length : longestLength;
      });
      // Fill with n 0s
      dummyLabel.innerHTML = new Array(longestLength + 1).join('0');
    } else {
      // Take the largest number
      dummyLabel.innerHTML = stats.y.max;
    }

    layoutOriginCenter.appendChild(dummyLabel);
    layoutYAxis.appendChild(dummyLabel);

    layoutOriginRight.setAttrs({
      style: 'width: 1%;',
    });


    // Y BASELINE
    // -----------------------
    if (stats.y.min < 0) {
      layoutChart.appendChild(new Baseline({
        type: 'y',
        stats,
        stroke: config.baseline.style.stroke,
        width: config.baseline.style['stroke-width'],
      }).render());
    }

    // X BASELINE
    // -----------------------
    if (stats.x.min < 0) {
      layoutChart.appendChild(new Baseline({
        type: 'x',
        stats,
        stroke: config.baseline.style.stroke,
        width: config.baseline.style['stroke-width'],
      }).render());
    }

    // PLOT CONTAINERS
    // -----------------------
    /*
     Create the graph. We'll need two containers,
     one that scales and one that maintains aspect ratio
    */
    const subchartStretch = this.createGraph({
      stretch: true,
    });
    layoutChart.appendChild(subchartStretch);

    const subchartNoStretch = this.createGraph({
      stretch: false,
    });
    layoutChart.appendChild(subchartNoStretch);


    // PLOT
    // -----------------------
    this.createPlot({
      data,
      stats,
      subchartStretch,
      subchartNoStretch,
    });

    // Add post-styles once the chart is painted
    const postStyle = new VElement('style');
    postStyle.innerHTML = `.plot {opacity: 1;} .svc-loading {opacity:0;}`;
    layoutChart.appendChild(postStyle);

    // TOOLTIP
    // -----------------------

    // Add responsive media queries to handle scale text
    stylesheet.addRaw(createMediaQueries({stats, config}));

    return structure;
  }

  /**
   * Create the tooltip script code
   * @return {object} Containing the tooltip element
   */
  createScript() {
    return (new Tooltip({
      stats: this.stats,
      data: this.data,
      config: this.config,
    })).render();
  }

  /**
   * Creates a virtual dom element for either the x or y axis.
   * @param {object} obj.type - Which axis to create
   * @return {object} virtual dom element
   */
  createAxis({type}) {
    if (type === 'x') {
      return new VElement('line', {
        'x1': '0%',
        'x2': '100%',
        'y1': '100%',
        'y2': '100%',
        'class': ['axis', 'axis-x'],
      });
    } else {
      return new VElement('line', {
        'x1': '0%',
        'x2': '0%',
        'y1': '0%',
        'y2': '100%',
        'class': ['axis', 'axis-y'],
      });
    }
  }

  /**
   * Calculates information from the data to be used in scaling and plotting data
   * points.
   * @param {object} data - The user supplied data
   * @param {SVCConfig} config - The user supplied configuration object
   * @return {object} The stats object
   * @throws {Error} If `data` is not a non-empty array.
   * @throws {Error} If any series element is missing a `values` property.
   */
  calculateStats(data, config) {
    if (!Array.isArray(data) || data.length === 0) {
      throw new Error('SVC: "data" must be a non-empty array of series objects.');
    }
    for (let i = 0; i < data.length; i++) {
      if (!data[i] || data[i].values == null) {
        throw new Error(`SVC: data[${i}] must have a "values" property.`);
      }
    }

    const keyStats = {
      min: Infinity,
      max: -Infinity,
      ticks: DEFAULT_Y_TICKS,
      scale: 0,
    };

    const valueStats = {
      min: Infinity,
      max: -Infinity,
      ticks: DEFAULT_VALUE_TICKS,
      scale: 0,
    };
    const altStats = {
      min: Infinity,
      max: -Infinity,
    };

    let associative = false;

    // Obtain the interval (min, max) of x & y
    const chartType = this.constructor.type;
    let largestSeriesLength = -Infinity;

    // Obtain the min and max of the key/value set.
    if (chartType === 'scatter' || chartType === 'bubble') {
      Object.assign(keyStats, getScatterInterval(data, 'x'));
      Object.assign(valueStats, getScatterInterval(data, 'y'));

      if (chartType === 'bubble') {
        Object.assign(altStats, getScatterInterval(data, 'size'));
      }
      // Key-value pairs
      // Test the first series if it is k/v based
    } else if (!Array.isArray(data[0].values)) {
      associative = true;
      const values = data
          .reduce((acc, series) => {
            return acc.concat(Object.keys(series.values)
                .map((key) => {
                  return series.values[key];
                }));
          }, [])
          .sort((a, b) => {
            return a - b;
          });

      /*
      Length of the series. Create an array of all unique keys.
        Order will be predicated on user order in which unique keys appear unless sorting is enabled
      */
      // Squash all objects into one object, overwriting values. Then take the Object.keys
      let keys = {};
      data.forEach((series) => {
        Object.assign(keys, series.values);
      });
      keys = Object.keys(keys);
      if (config.scale.sorted) {
        keys.sort();
      }
      valueStats.min = values[0];
      valueStats.max = values[values.length - 1];
      keyStats.keys = keys;
      keyStats.min = 0;
      keyStats.max = largestSeriesLength = keys.length;
    } else {
      // Min and Max of the values
      const values = data
          .reduce((acc, series) => {
            return acc.concat(series.values);
          }, [])
          .sort((a, b) => {
            return a - b;
          });
      valueStats.min = values[0];
      valueStats.max = values[values.length - 1];

      // Length of the series
      const firstLength = data[0].values.length;
      data.forEach((series, i) => {
        if (series.values.length !== firstLength) {
          console.warn(
            `SVC: Series ${i} has ${series.values.length} values, but series 0 has ${firstLength}. Mismatched lengths may cause unexpected results.`,
          );
        }
        largestSeriesLength = (series.values.length > largestSeriesLength) ?
        series.values.length : largestSeriesLength;
      });
      keyStats.min = 0;
      keyStats.max = largestSeriesLength;
    }

    Object.assign(valueStats, calculateScale(valueStats));

    // SCALE KEY
    if (chartType === 'scatter' || chartType === 'bubble') {
      Object.assign(keyStats, calculateScale(keyStats));
    } else if (chartType === 'bar' || chartType === 'column') {
      // Try to find the best number of ticks for the dataset length
      if (largestSeriesLength > config.scale.maxItems) {
        keyStats.ticks = config.scale.maxItems;
        keyStats.step = Math.floor((largestSeriesLength) / (keyStats.ticks-1));
      } else {
        keyStats.ticks = largestSeriesLength;
        keyStats.step = 1;
      }
      keyStats.scaleLength = largestSeriesLength;
      keyStats.scaleFactor = (Util.formatNumber(100 / (largestSeriesLength)));
    } else {
      // Try to find the best number of ticks for the dataset length
      if (largestSeriesLength > config.scale.maxItems) {
        keyStats.ticks = config.scale.maxItems;
        keyStats.step = Math.ceil((largestSeriesLength) / (keyStats.ticks-1));
      } else {
        keyStats.ticks = largestSeriesLength;
        keyStats.step = 1;
      }
      keyStats.scaleLength = largestSeriesLength;
      keyStats.scaleFactor = (Util.formatNumber(100 / (largestSeriesLength - 1)));
    }

    const isVertical = config.plot.vertical;
    return {
      associative,
      x: (isVertical) ? keyStats : valueStats,
      y: (isVertical) ? valueStats : keyStats,
      alt: altStats,
    };

    /**
    * Calculates a scale for y, and negative x values when the dataset is non-linear
    * @param {object} - the min, max, and number of ticks.
    * @return {object} An object containing information about the scales
    */
    function calculateScale({max, min, ticks: numTicks}) {
      // Increase the max/ min by 10% for a buffer area.
      min = Math.floor(min + (min * SCALE_BUFFER_PERCENT));
      max = Math.ceil(max + (max * SCALE_BUFFER_PERCENT));
      // Force a minimum value of 0 if not negative
      min = (min > 0) ? 0 : min;

      // Calculate a nice step size that produces round tick values
      const rawInterval = max - min;
      const step = niceStep(rawInterval, numTicks);

      // Snap min down and max up to step boundaries
      min = Math.floor(min / step) * step;
      max = Math.ceil(max / step) * step;

      const scaleLength = max - min;
      numTicks = Math.round(scaleLength / step) + 1;

      const scaleFactor = (100 / scaleLength);

      return {min, max, step, scaleLength, scaleFactor, ticks: numTicks};
    }

    /**
     * Calculate a "nice" step size for axis ticks.
     * Produces round numbers like 1, 2, 5, 10, 20, 25, 50, 100, etc.
     * @param {number} range - the data range (max - min)
     * @param {number} targetTicks - desired number of tick intervals
     * @return {number} a round step value
     */
    function niceStep(range, targetTicks) {
      const rawStep = range / targetTicks;
      const magnitude = Math.pow(10, Math.floor(Math.log10(rawStep)));
      const residual = rawStep / magnitude;

      let niceRes;
      if (residual <= 1.5) niceRes = 1;
      else if (residual <= 3.5) niceRes = 2.5;
      else if (residual <= 7.5) niceRes = 5;
      else niceRes = 10;

      return niceRes * magnitude;
    }
  }
  // {timestamp, dataset, stats, instance}
  /**
 * Manages event movement and timing of a tooltip
 * @param {*} state
 * @param {*} instance
 * @param {*} chart
 */
  tooltipInteraction(state, instance, chart) {
    const target = instance.getElementsByClassName('svc-l-plotarea')[0];
    const tooltipElement = instance.querySelector('#svc-tooltip-box');

    const tooltipTextElement = instance.querySelector('#svc-tooltip-label');
    const crosshairElement = instance.querySelector('.svc-tooltip-crosshair');

    let tooltipText = '';
    let lastUpdated = 0;
    let activeNodes = [];
    let hideTimeoutId = null;
    let debounceTimeoutId = null;

    function hideTooltip() {
      tooltipTextElement.setAttribute('class', 'svc-tooltip-label svc-hide');
      tooltipElement.setAttribute('class', 'svc-tooltip svc-hide');
      for (let i = 0; i < activeNodes.length; i++) {
        activeNodes[i].classList.remove('svc-plot-node-active-' + i);
      }
      activeNodes = [];
    }

    function resetHideTimer() {
      if (hideTimeoutId) clearTimeout(hideTimeoutId);
      hideTimeoutId = setTimeout(hideTooltip, TOOLTIP_HIDE_DELAY_MS);
    }

    target.addEventListener('mousedown', execute);
    target.addEventListener('mousemove', execute);

    // Store cleanup references on state for destroy()
    state._tooltipCleanup = function() {
      if (hideTimeoutId) clearTimeout(hideTimeoutId);
      if (debounceTimeoutId) clearTimeout(debounceTimeoutId);
      target.removeEventListener('mousedown', execute);
      target.removeEventListener('mousemove', execute);
    };

    /**
     * The event handler for tooltips.
     * @param {Object} e - the Event object
     */
    function execute(e) {
      resetHideTimer();
      const info = state.functions.tooltipLocation(e, state, instance, chart);
      if (!info) return;
      tooltipText = info.tooltip.text;
      // Set which nodes are active, and deactivate old ones
      const nodes = instance.querySelectorAll('.svc-plot-node[node="' + info.index + '"]');
      for (let i = 0; i < activeNodes.length; i++) {
        activeNodes[i].classList.remove('svc-plot-node-active-' + i);
      }
      activeNodes = [];
      for (let i = 0; i < nodes.length; i++) {
        nodes[i].classList.add('svc-plot-node-active-' + i);
        activeNodes.push(nodes[i]);
      }

      crosshairElement.setAttribute('x1', info.crosshair.x1 + '%');
      crosshairElement.setAttribute('x2', info.crosshair.x2 + '%');
      crosshairElement.setAttribute('y1', info.crosshair.y1 + '%');
      crosshairElement.setAttribute('y2', info.crosshair.y2 + '%');

      const fo = tooltipElement.children[1];
      fo.setAttribute('x', info.tooltip.x + '%');
      fo.setAttribute('y', info.tooltip.y + '%');
      tooltipTextElement.setAttribute('class', 'svc-tooltip-label');
      tooltipElement.setAttribute('class', 'svc-tooltip');

      if (debounceTimeoutId) clearTimeout(debounceTimeoutId);
      debounceTimeoutId = setTimeout(function() {
        if ((new Date().getTime() - lastUpdated) > TOOLTIP_DEBOUNCE_MS) {
          tooltipTextElement.innerHTML = tooltipText;
          lastUpdated = new Date().getTime();
        }
      }, TOOLTIP_DEBOUNCE_MS);
    }
  }

  /**
   * Event handler for legend clicks
   * @param {*} state - the internal state to determine which plots are visible/hidden
   * @param {*} instance - the SVC instance for the chart
   */
  legendInteraction(state, instance) {
    state.toggles = Array.from(instance.querySelectorAll('.svc-legend-item input'));
    state.toggles.forEach((toggle) => {
      toggle.removeAttribute('onclick');
      toggle.addEventListener('click', (e) => {
        const series = e.target.getAttribute('data-series');
        state.toggles[series] = e.target.checked;
        instance.getElementsByClassName('svc-plot-' + series)[0].style.opacity = state.toggles[series] ? 1: 0;
        const nodes = instance.getElementsByClassName('svc-plot-node-' + series);
        for (let i = 0; i < nodes.length; i++) {
          nodes[i].style.opacity = state.toggles[series] ? 1: 0;
        }
      });
    });
  }
}

/**
 * Gets the min and max for scatter/bubble charts
 * @param {object} data - the user supplied data
 * @param {string} axis - which axis
 * @return {object} contains min and max values
 */
function getScatterInterval(data, axis) {
  let index;
  switch (axis) {
    case 'x':
      index = 0;
      break;
    case 'y':
      index = 1;
      break;
    case 'size':
      index = 2;
      break;
  }

  const values = data
      .map((series) => {
        return series.values.map((value) => {
          return value[index];
        });
      })
      .reduce((acc, arr) => {
        return acc.concat(arr);
      })
      .sort((a, b) => {
        return a - b;
      });
  return {
    min: values[0],
    max: values[values.length - 1],
  };
}

export default Cartesian;
