/**
 * Creates media queries for the chart's responsiveness
 * @param {object} obj.stats - the statistics object to hold chart info
 * @param {config} obj.config - the user supplied conifg
 * @return {string} Media Queries as a string
 */
function createMediaQueries({stats, config}) {
  const minFontSize = config.scale.minFontSize;
  const maxTicks = config.scale.maxItems;

  /*
    We'll create media queries and let the font-size: viewport and
    ellipsis take care of the inbetweens. These media queries will control hiding n number of labels
  */

  let compiledQueries = '';
  // General text sizing:
  compiledQueries += `
    .svc-scale-label-x,
    .svc-scale-label-y,
    .svc-guides-x,
    .svc-guides-y,
    .svc-ticks-x,
    .svc-ticks-y {
      opacity: 0;
    }
    .svc-scale-label-x, .svc-scale-label-y, .svc-l-axis-y-label,  .svc-l-axis-x-label {
      font-size: calc(${minFontSize}px + 1vmin);
      padding: calc(4px + 0.1vmin);
      box-sizing: border-box;
    }
    .svc-l-axis-y-label {
      padding: calc(5px + 0.1vmin);
      padding-right: 10px;
    }
  `;


  // Set a standard scale-x width for ellipsis
  const width = parseFloat(((100/maxTicks) - 1).toFixed(2));
  compiledQueries += `
    .svc-scale-label-x {
      width: calc(${width}% - 5px);
      max-width: calc(${width}%);
    }`;


  const queries = {
    '0': 2,
    '250': 4,
    '600': 6,
    '800': 10,
    '1000': maxTicks,
  };

  const axis = ['x', 'y'];
  axis.forEach((axis) => {
    const queryKeys = Object.keys(queries);
    const d = (axis === 'x') ? 'width': 'height';
    queryKeys.forEach((query, index) => {
      let rule;
      const numTicks = Math.floor(maxTicks/queries[query]);
      const minPoint = parseInt(query);
      const maxPoint = parseInt(queryKeys[index+1]) - 1;

      if (index === 0) {
        if (d === 'width') {
          rule = `
            @media(max-${d}: ${maxPoint}px) {
              .svc-scale-label-${axis}:first-child,
              .svc-scale-label-${axis}:nth-last-child(2),
              .svc-guides-x:first-child,
              .svc-guides-x:nth-last-child(2),
              .svc-ticks-x:first-child,
              .svc-ticks-x:nth-last-child(2) {
                opacity: 1;
              }
              .svc-scale-label-${axis} {
                ${d}: calc(50% - 5px);
                max-${d}: 50%;
              }
            }
          `;
        } else {
          rule = `
            @media(max-${d}: ${maxPoint}px) {
              .svc-scale-label-${axis}:first-child,
              .svc-scale-label-${axis}:nth-last-child(2),
              .svc-guides-x:first-child,
              .svc-guides-x:nth-last-child(2),
              .svc-ticks-x:first-child,
              .svc-ticks-x:nth-last-child(2) {
                opacity: 1;
              }
            }
          `;
        }
      } else if (index === queryKeys.length - 1) {
        rule = `
          @media(min-${d}: ${queryKeys[index]}px) {
            .svc-scale-label-${axis},
            .svc-guides-${axis},
            .svc-ticks-${axis} {
              opacity: 1;
            }
          }
        `;
      } else {
        const length = parseFloat((100/(numTicks + 1)).toFixed(2));
        // Number of guides !== number of ticks/labels for x and y
        const guideQuanitfier = (axis === 'x') ? '': ' + 1';
        rule = `@media(min-${d}: ${minPoint}px) and (max-${d}: ${maxPoint}px) {`;
        rule += `
          .svc-scale-label-${axis}:nth-child(${numTicks}n + 1),
          .svc-guides-${axis}:nth-child(${numTicks}n ${guideQuanitfier}),
          .svc-ticks-${axis}:nth-child(${numTicks}n + 1) {
            opacity: 1;
          }
        `;
        if (axis === 'x') {
          rule += `
            .svc-scale-label-x {
              width: calc(${length}% - 5px);
              max-width: calc(${length}%);
            }
          `;
        }
        rule += '}';
      }
      compiledQueries += rule;
    });
  });

  return compiledQueries;
};

export default createMediaQueries;
