import Cartesian from './Cartesian.js';
import VElement from '../DOM/VElement.js';
import {TOOLTIP_DEBOUNCE_MS, TOOLTIP_HIDE_DELAY_MS} from '../constants.js';

/**
 * Scatter Chart
 * @example
 * const chart = new ScatterChart({
 *   data: [
 *     { name: 'Group A', values: [[1, 2], [3, 5], [6, 4]] },
 *   ],
 *   config: { title: { text: 'X vs Y' } },
 * });
 * const svg = chart.toString();
 */
class ScatterChart extends Cartesian {
  /**
   * Returns the stringified name of the chart type
   * @return {string} The type of the chart
   */
  static get type() {
    return 'scatter';
  }

  /**
   * Returns the default object configuration for the chart type
   * @return {object} Returns the defaults objct
   */
  static get defaults() {
    return {
      plot: {
        size: 4,
      },
    };
  }

  /**
   * Return the specifications object for the chart. Used to apply styling
   * such as fills and strokes to different parts of the SVG
   * @return {object}
   */
  static specs() {
    return {
      'plot.node': {
        fill: 'primary',
      },
    };
  }

  /**
   * Manages event movement and timing of a tooltip
   * @param {*} state
   * @param {*} instance
   * @param {*} chart
   */
  tooltipInteraction(state, instance, chart) {
    const target = instance.getElementsByClassName('svc-l-plotarea')[0];
    const tooltipElement = instance.querySelector('#svc-tooltip-box');

    const tooltipTextElement = instance.querySelector('#svc-tooltip-label');
    const crosshairElement = instance.querySelector('.svc-tooltip-crosshair');

    let tooltipText = '';
    let lastUpdated = 0;
    let activeNodes = [];
    let hideTimeoutId = null;
    let debounceTimeoutId = null;

    function hideTooltip() {
      tooltipTextElement.setAttribute('class', 'svc-tooltip-label svc-hide');
      tooltipElement.setAttribute('class', 'svc-tooltip svc-hide');
      for (let i = 0; i < activeNodes.length; i++) {
        activeNodes[i].classList.remove('svc-plot-node-active-' + i);
      }
      activeNodes = [];
    }

    function resetHideTimer() {
      if (hideTimeoutId) clearTimeout(hideTimeoutId);
      hideTimeoutId = setTimeout(hideTooltip, TOOLTIP_HIDE_DELAY_MS);
    }

    target.addEventListener('mousedown', execute);
    target.addEventListener('mousemove', execute);

    state._tooltipCleanup = function() {
      if (hideTimeoutId) clearTimeout(hideTimeoutId);
      if (debounceTimeoutId) clearTimeout(debounceTimeoutId);
      target.removeEventListener('mousedown', execute);
      target.removeEventListener('mousemove', execute);
    };

    state.nodeMap = state.nodeMap || createNodeMap(chart.data, instance);

    /**
     * Creates a fuzzy region map for mouse over events to detect nearby nodes.
     * @param {*} data
     * @param {*} instance
     * @return {object} A 3D array of nodes in proximity
     */
    function createNodeMap(data, instance) {
      const nodeMap = Array.from(new Array(10)).map(() => Array.from(new Array(10)).map(() => []));
      instance.querySelectorAll('.svc-plot-node').forEach((node) => {
        const series = node.getAttribute('data-series');
        const x = parseInt(node.getAttribute('cx'));
        const y = parseInt(node.getAttribute('cy'));
        const xTens = Math.floor(x / 10);
        const xOnes = parseInt((x / 10).toFixed(1).split('.')[1]);
        const yTens = Math.floor(y / 10);
        nodeMap[yTens][xTens][xOnes] = nodeMap[yTens][xTens][xOnes] || [];

        nodeMap[yTens][xTens][xOnes][series] = node;
      });
      return nodeMap;
    }

    /**
     * The event handler for tooltips.
     * @param {Object} e - the Event object
     */
    function execute(e) {
      resetHideTimer();
      const info = state.functions.tooltipLocation(e, state, instance, chart);
      if (!info) return;
      tooltipText = info.tooltip.text;
      // Set which nodes are active, and deactivate old ones
      const nodes = instance.querySelectorAll('.svc-plot-node[node="' + info.index + '"]');
      for (let i = 0; i < activeNodes.length; i++) {
        activeNodes[i].classList.remove('svc-plot-node-active-' + i);
      }
      activeNodes = [];
      for (let i = 0; i < nodes.length; i++) {
        nodes[i].classList.add('svc-plot-node-active-' + i);
        activeNodes.push(nodes[i]);
      }

      crosshairElement.setAttribute('x1', info.crosshair.x1 + '%');
      crosshairElement.setAttribute('x2', info.crosshair.x2 + '%');
      crosshairElement.setAttribute('y1', info.crosshair.y1 + '%');
      crosshairElement.setAttribute('y2', info.crosshair.y2 + '%');

      const fo = tooltipElement.children[1];
      fo.setAttribute('x', info.tooltip.x + '%');
      fo.setAttribute('y', info.tooltip.y + '%');
      tooltipTextElement.setAttribute('class', 'svc-tooltip-label');
      tooltipElement.setAttribute('class', 'svc-tooltip');

      if (debounceTimeoutId) clearTimeout(debounceTimeoutId);
      debounceTimeoutId = setTimeout(function() {
        if ((new Date().getTime() - lastUpdated) > TOOLTIP_DEBOUNCE_MS) {
          tooltipTextElement.innerHTML = tooltipText;
          lastUpdated = new Date().getTime();
        }
      }, TOOLTIP_DEBOUNCE_MS);
    }
  }

  /**
   * Callback function for mousehover events on the plot. Determines the location
   * of the tooltip along with the chart's data to be displayed as text.
   * @param {*} state
   * @param {*} instance
   * @param {*} chart
   * @return {object} the tooltip info object
   */
  tooltipLocation(state, instance, chart) {
    return function tooltipLocation(e) {
      const info = {
        tooltip: {},
        crosshair: {},
      };

      const tooltipOffset = 1;
      let tooltipText = '';
      const tooltipTextElement = instance.querySelector('#svc-tooltip-label');
      const target = instance.getElementsByClassName('svc-l-plotarea')[0];
      const box = target.getBoundingClientRect();
      let xPercent = (((e.clientX - box.left)/ box.width));
      let yPercent = (((e.clientY - box.top)/ box.height));

      xPercent = Math.floor(xPercent * 100);
      yPercent = Math.floor(yPercent * 100);

      const xTens = Math.floor(xPercent/10);
      const xOnes = parseInt((xPercent/10).toFixed(1).split('.')[1]);
      const yTens = Math.floor(yPercent/10);
      let nodes;
      if (state.nodeMap[yTens] && state.nodeMap[yTens][xTens]) {
        nodes = state.nodeMap[yTens][xTens][xOnes];
      } else {
        return;
      }

      if (!nodes) {
        return;
      }

      const targetBbox = target.getBoundingClientRect();
      const tooltipBbox = tooltipTextElement.getBoundingClientRect();

      // Disable crosshair
      info.crosshair.x1 = -1;
      info.crosshair.x2 = -1;
      info.crosshair.y1 = -1;
      info.crosshair.y2 = -1;

      // Tooltip Position
      if (xPercent > 50) {
        info.tooltip.x = xPercent - ((tooltipBbox.width / targetBbox.width)*100) - tooltipOffset;
      } else {
        info.tooltip.x = xPercent + tooltipOffset;
      }
      info.tooltip.y = yPercent;
      nodes.forEach((node) => {
        const series = node.getAttribute('data-series');
        const index = node.getAttribute('data-index');
        const data = chart.data[series].values[index];
        const name = chart.data[series].name;
        let content;
        if (chart.config.tooltip.format) {
          try {
            content = chart.config.tooltip.format(name, data);
          } catch (e) {
            console.warn('SVC: tooltip.format threw an error:', e);
            content = data;
          }
        } else {
          content = data;
        }
        tooltipText += `<div class="svc-tooltip-content">
          <span class="svc-tooltip-label-title svc-tooltip-label-title-${series}">${name}></span> : (${content})
        </div>`;
      });
      info.tooltip.text = tooltipText;
      return info;
    };
  }

  /**
  * Creates the plot and markers from the user provided data.
  * @param {object} data - the user supplied data
  * @param {object} stats - the computed constraints of the chart
  * @param {object} subchartStretch - the parent VElement container
  */
  createPlot({
    data,
    stats,
    subchartNoStretch,
  }) {
    data.forEach((series, index) => {
      const values = series.values;
      values.forEach((pair, nodeindex) => {
        const x = pair[0];
        const y = pair[1];
        const nodeCircle = new VElement('circle', {
          'cx': ((x - stats.x.min) * stats.x.scaleFactor).toFixed(3) + '%',
          'cy': ((stats.y.max - y) * stats.y.scaleFactor).toFixed(3) + '%',
          'r': this.config.plot.size,
          'class': ['plot-node', `plot-${index}`, `plot-node-${index}`],
          'data-index': nodeindex,
          'data-series': index,
        });
        subchartNoStretch.appendChild(nodeCircle);
      });
    });
  }
}

export default ScatterChart;
