import VElement from '../DOM/VElement.js';
import {escapeHtml} from '../utils/Utils.js';

/**
 * Legend class
 */
class Legend {
  /**
   * @param {object} obj.config - the user config object
   * @param {object} obj.data - the user data
   */
  constructor({config, data}) {
    this.config = config;
    this.data = data;
  }

  /**
   * Returns the defaults for the legend object
   */
  static get defaults() {
    const breakpoint = {
      width: 300,
      height: 275,
    };
    return {
      l: {
        chart: {
          row: {
            2: {breakpoint},
          },
        },
        legend: {
          breakpoint,
        },
      },
      legend: {
        breakpoint,
        enabled: true,
        style: {
          'margin': 0,
          'padding': 0,
          'flex-direction': 'column',
          'flex-wrap': 'wrap',
          'justify-content': 'center',
          'background-color': 'var(--color-surface, rgba(255,255,255,0.8))',
          'z-index': 2,
        },
        item: {
          style: {
            'display': 'flex',
            'align-items': 'center',
            'padding': '0.5em',
            'color': 'var(--chart-label-color, #616161)',
            'white-space': 'nowrap',
          },
        },
      },
    };
  }


  /**
   * Legend render
   * @param {*} stylesheet
   * @param {*} structure
   * @param {*} type
   * @return {object} virtual dom of legend
   */
  render(stylesheet, structure, type) {
    return this.createLegend(this.config, this.data, stylesheet, structure, type);
  }

  /**
   * Creates the legend object
   * @param {*} config
   * @param {*} series
   * @param {*} stylesheet
   * @param {*} structure
   * @param {*} chartType
   * @return {object} virtual dom of legend
   */
  createLegend(config, series, stylesheet, structure, chartType) {
    const legend = new VElement('ul', {
      class: ['legend'],
    });
    let html = '';
    const timestamp = new Date().getTime();

    const items = (chartType !== 'pie')
        ? this.data.map((s, i) => ({name: s.name || 'Series ' + i, index: i}))
        : Object.keys(this.data).map((key, i) => ({name: key, index: i}));

    items.forEach(({name, index}) => {
      html += `<li class="svc-legend-item">
        <input class="svc-legend-toggle svc-styled-checkbox svc-series-${index}"
               type="checkbox" id="legend-item-${index}-${timestamp}"
               data-series="${index}"
               checked=""/>
        <label id="legend-item-text-${index}-${timestamp}"
          for="legend-item-${index}-${timestamp}">
          ${escapeHtml(name)}
        </label>
      </li>`;

      let plotColors;
      if (this.config.plot.instances && this.config.plot.instances.length > 0) {
        plotColors = this.config.plot.instances[index % this.config.plot.instances.length];
      } else if (this.config.plot.node.instances &&
          this.config.plot.node.instances.length > 0) {
        plotColors = this.config.plot.node.instances[index % this.config.plot.node.instances.length];
      }

      let color = '#777';
      if (plotColors && plotColors.stroke) {
        color = plotColors.stroke;
      } else if (plotColors && plotColors.fill) {
        color = plotColors.fill;
      }

      stylesheet.addRule(`styled-checkbox.svc-series-${index}:checked + label:before `, {
        background: color,
      });
    });

    // Also update the series names in-place for non-pie charts
    if (chartType !== 'pie') {
      this.data.forEach((series, index) => {
        series.name = series.name || 'Series ' + index;
      });
    }

    legend.innerHTML = html;
    return legend;
  }
}


export default Legend;
