import VElement from './VElement.js';

/**
  Creates the SVG Skeleton for the chart, title, legend, and axis
  +---svg
  |    +---foreignObject
  |    |   +---wrap
  |    |   |   +---top
  |    |   |   |   +---title
  |    |   |   +---body
  |    |   |   |   +---y-axis-label
  |    |   |   |   +---chart
  |    |   |   |   |   +---chart-row
  |    |   |   |   |   |   +---y-axis
  |    |   |   |   |   |   +---plotarea
  |    |   |   |   |   +---chart-row
  |    |   |   |   |   |   +---origin-cell
  |    |   |   |   |   |   +---x-axis
  |    |   |   |   |   +---chart-row
  |    |   |   |   |   |   +---x-axis-label
  |    |   |   |   +---legend
  * @return {Object} - An object containing all of the structural virtualDOM elements
  */
function createSVGContainer() {
  // The root wraps the entire chart so it can be portable and embedable.
  const root = new VElement('svg');
  const svgAttrs = {
    'width': '100%',
    'height': '100%',
    'xmlns': 'http://www.w3.org/2000/svg',
    'role': 'img',
  };
  root.setAttrs(svgAttrs);

  /*
    Everything besides the main style element is wrapped inside of a
    foreignObject to utilize flexbox's flexible layout for the legend, and
    label items.
  */
  const fo = new VElement('foreignObject', {
    width: '100%',
    height: '100%',
  });
  root.appendChild(fo);
  const foBody = new VElement('body', {
    xmlns: 'http://www.w3.org/1999/xhtml',
    style: 'width:100%;height:100%;',
  });
  fo.appendChild(foBody);
  foBody.appendChild(new VElement('meta', {
    name: 'viewport',
    content: 'width=device-width, initial-scale=1',
  }));

  // The main wrapper — a <figure> since a chart is a self-contained illustration
  const wrap = new VElement('figure', {
    class: ['l-wrap', 'container'],
  });
  foBody.appendChild(wrap);

  // Contains the title (figcaption within the figure)
  const top = new VElement('figcaption', {
    class: ['l-top'],
  });
  wrap.appendChild(top);

  // Contains the scales, chart, and the legend
  const body = new VElement('section', {
    class: ['l-body'],
  });
  wrap.appendChild(body);

  // CHART
  // -----------------------
  const chart = new VElement('section', {
    'class': ['l-chart'],
    // 'data-type': this.config.type,
  });
  body.appendChild(chart);

  // CHART - row 0
  // y-axis labels, ticks, axis name, plotarea
  // -----------------------
  const chartRow0 = new VElement('section', {
    class: ['l-chart-row-0'],
  });

  const layoutYAxisLabel = new VElement('section', {
    class: ['l-axis-y-label'],
  });

  chartRow0.appendChild(layoutYAxisLabel);

  const layoutYAxis = new VElement('section', {
    class: ['l-axis-y', 'l-axis'],
  });
  chartRow0.appendChild(layoutYAxis);

  const layoutYTicks = new VElement('svg', {
    'width': '100%',
    'xmlns': 'http://www.w3.org/2000/svg',
    'class': ['l-ticks-y'],
  });
  chartRow0.appendChild(layoutYTicks);

  const plotarea = new VElement('section', {
    class: ['l-plotarea'],
  });
  chartRow0.appendChild(plotarea);
  const layoutChart = new VElement('svg');
  layoutChart.setAttrs({
    'width': '100%',
    'xmlns': 'http://www.w3.org/2000/svg',
    'class': ['plotarea'],
  });
  plotarea.appendChild(layoutChart);

  // CHART - row 1
  // origin cell, x-axis labels, ticks,
  // -----------------------
  const chartRow1 = new VElement('section', {
    class: ['l-chart-row-1'],
  });

  const layoutOriginLeft = new VElement('section', {
    class: ['l-origin-left', 'l-axis-y-label'],
  });
  // if(this.config.axis.label.y.enabled) {
  //   chartRow1.appendChild(layoutOriginLeft);
  // }
  chartRow1.appendChild(layoutOriginLeft);

  const layoutOriginCenter = new VElement('section', {
    class: ['l-origin-center'],
  });
  chartRow1.appendChild(layoutOriginCenter);

  const layoutOriginRight = new VElement('section', {
    class: ['l-origin-right'],
  });
  chartRow1.appendChild(layoutOriginRight);

  const xAxisWrapper = new VElement('div', {
    class: ['l-axis-x-wrap'],
  });
  chartRow1.appendChild(xAxisWrapper);

  const layoutXTicks = new VElement('svg', {
    'width': '100%',
    'xmlns': 'http://www.w3.org/2000/svg',
    'class': ['l-ticks-x'],
  });

  xAxisWrapper.appendChild(layoutXTicks);

  const layoutXAxis = new VElement('section', {
    class: ['l-axis-x', 'l-axis'],
  });
  xAxisWrapper.appendChild(layoutXAxis);

  // CHART - row 2
  // origin cell, x-axis labels, ticks,
  // -----------------------
  const chartRow2 = new VElement('section', {
    class: ['l-chart-row-2'],
  });
  const layoutXAxisLabel = new VElement('div', {
    class: ['l-axis-x-label'],
  });

  chartRow2.appendChild(layoutXAxisLabel);

  /*
    Reverse append the rows; .svc-l-chart will have column-reverse as a flex property.
    We do this so the tooltip overlaps the scale-y labels properly. (z-index stacking order)
  */
  chart.appendChild(chartRow2);
  chart.appendChild(chartRow1);
  chart.appendChild(chartRow0);

  // const {layoutChart} = structure;


  // PLOTAREA
  // -----------------------
  layoutChart.appendChild(new VElement('rect', {
    x: '0%',
    y: '0%',
    width: '100%',
    height: '100%',
    class: ['plotarea'],
  }));

  // LOADING STATUS
  // -----------------------
  const loading = new VElement('text', {
    x: '50%',
    y: '50%',
    class: ['loading'],
  });
  loading.innerHTML = 'Loading Chart...';
  layoutChart.appendChild(loading);


  return {
    root,
    top,
    body,
    layoutChart,
    layoutXAxis,
    layoutYTicks,
    layoutXTicks,
    layoutYAxis,
    layoutOriginRight,
    layoutOriginCenter,
    layoutXAxisLabel,
    layoutYAxisLabel,
    layoutOriginLeft,
  };
}

export default createSVGContainer;
